diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..e48c00a1a346 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4562,6 +4562,22 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
       (Pred == ICmpInst::ICMP_UGT || Pred == ICmpInst::ICMP_ULE))
     return new ICmpInst(Pred, X, Builder.CreateNot(Op0));

+  // (~A ^ B) cmp (~C) --> (A ^ B) (flipped_cmp) C
+  // ((X ^ -1) ^ Y) s< (X ^ -1) --> (X ^ Y) s> X (special case where C = A)
+  // This uses the identity: (~X) cmp (~Y) <=> X (flipped_cmp) Y
+  // Valid for both signed and unsigned non-equality comparisons.
+  if (!ICmpInst::isEquality(Pred)) {
+    Value *A, *B, *C;
+    // Match Op0 as (~A ^ B) = ((A ^ -1) ^ B)
+    if (match(Op0, m_OneUse(m_c_Xor(m_c_Xor(m_Value(A), m_AllOnes()), m_Value(B))))) {
+      // Match Op1 as ~C = (C ^ -1)
+      if (match(Op1, m_c_Xor(m_Value(C), m_AllOnes()))) {
+        CmpInst::Predicate NewPred = ICmpInst::getSwappedPredicate(Pred);
+        return new ICmpInst(NewPred, Builder.CreateXor(A, B), C);
+      }
+    }
+  }
+
   {
     // (Op1 + X) + C u</u>= Op1 --> ~C - X u</u>= Op1
     Constant *C;

